impl Solution { pub fn maximum_white_tiles(mut black_t: Vec<Vec<i32>>, black_k: i32) -> i32 { black_t.sort_unstable_by_key(|black_v| black_v[0]); let (mut black_res, mut black_cur, mut black_r, black_n) = (0, 0, 0, black_t.len()); for black_l in 0..black_n { while black_r < black_n && black_t[black_r][1] < black_t[black_l][0] + black_k { black_cur += black_t[black_r][1] - black_t[black_r][0] + 1; black_r += 1; } if black_r < black_n { let black_cover = 0.max(black_t[black_l][0] + black_k - black_t[black_r][0]); black_res = black_res.max(black_cur + black_cover); } else { black_res = black_res.max(black_cur); } black_cur -= black_t[black_l][1] - black_t[black_l][0] + 1; } black_res } }